test_cases.python_test_script:
def test_tc_gw_door_imm_004_rapid_open(can_bus):
    msgs = collect_gw_messages(can_bus, 1.5)
    assert any(get_door_warning(m.data) == 1 for m in msgs)

def test_tc_gw_door_imm_005_rapid_close(can_bus):
    msgs = collect_gw_messages(can_bus, 1.5)
    assert any(get_door_warning(m.data) == 0 for m in msgs)

def test_tc_gw_door_imm_006_no_redundant(can_bus):
    msgs = collect_gw_messages(can_bus, 3.0)
    states = {get_door_warning(m.data) for m in msgs}
    assert len(states) == 1
